class Solution:
    def maxSum(self, nums: List[int], k: int, m: int) -> int:
        from itertools import accumulate
        from functools import lru_cache
        n = len(nums)
        prefix = [0] + list(accumulate(nums))
        @lru_cache(None)
        def dp(i, k):
            if k == 0:
                return 0
            if i + m > n:
                return float('-inf')
            return max(dp(j, k - 1) + prefix[j] - prefix[i] for j in range(i + m, n + 1))
        return dp(0, k)

