def max_sum_of_k_subarrays(nums, k, m):
    n = len(nums)
    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    def get_subarray_sum(left, right):
        return prefix_sum[right + 1] - prefix_sum[left]

    memo = {}

    def dp(i, k):
        if (i, k) in memo:
            return memo[(i, k)]
        if k == 0:
            return 0
        if i + m > n:
            return float('-inf')
        max_sum = float('-inf')
        for j in range(m, n - i + 1):
            max_sum = max(max_sum, get_subarray_sum(i, i + j - 1) + dp(i + j, k - 1))
        memo[(i, k)] = max_sum
        return max_sum

    return dp(0, k)

def max_sum_of_k_subarrays(nums, k, m):
    n = len(nums)
