    def get_subarray_sum(left, right):
        return prefix_sum[right + 1] - prefix_sum[left]

    memo = {}

    def dp(index, k):
        if k == 0:
            return 0
        if (index, k) in memo:
            return memo[(index, k)]
        max_sum = float('-inf')
        for i in range(index, n - m + 1):
            for j in range(i + m - 1, n):
                subarray_sum = get_subarray_sum(i, j)
                max_sum = max(max_sum, subarray_sum + dp(j + 1, k - 1))
        memo[(index, k)] = max_sum
        return max_sum

    return dp(0, k)

