def get_subarrays(nums, k, m):
    n = len(nums)
    subarrays = []
    for i in range(n):
        for j in range(i + m, n + 1):
            subarray = nums[i:j]
            if len(subarray) >= m:
                subarrays.append(subarray)
    subarrays = sorted(subarrays, key=sum, reverse=True)
    return subarrays[:k]

def optimal_solution(nums, k, m):
    n = len(nums)
    max_sum = float('-inf')
    for mask in range(1 << n):
        subarrays = []
        start = 0
        for i in range(n):
            if (mask & (1 << i)) != 0:
                if i - start >= m:
                    subarrays.append(nums[start:i])
                start = i + 1
        if n - start >= m:
            subarrays.append(nums[start:])
        if len(subarrays) == k:
            max_sum = max(max_sum, sum(sum(subarray) for subarray in subarrays))
    return max_sum

